sequence.script:
var paymentDetails = JSON.parse(mc.getProperty("paymentDetails"));
var paymentId      = mc.getProperty("paymentId") || "";

var rawDt   = (paymentDetails.transactionDetails && paymentDetails.transactionDetails.dateTime)
                ? paymentDetails.transactionDetails.dateTime : "";
var payDate = "";
if (rawDt) {
  var parts = rawDt.split(/[\s\/\-]/);
  payDate = parts[2] + "-" + parts[1] + "-" + parts[0];
}

var now = new Date().toISOString();
// paybleIdentifier = "PA" + UUID-like string
var payableId = "PA" + java.util.UUID.randomUUID().toString();

var body = {
  "ledgerStatusCode":   "PAID",
  "transactionID":      paymentId,
  "paybleIdentifier":   payableId,
  "paymentDate":        payDate,
  "lastUpdatedDateTime":now,
  "transactionTypeCode":"NEW_CLAIM",
  "invoice": {
    "invoiceId": ""
  }
};
mc.setPayloadJSON(body);
